    const uint32_t Cin_check = GetDim(wsq_shape, 1);
    const uint32_t Ce1 = GetDim(wex1_shape, 0);
    const uint32_t Cs_check1 = GetDim(wex1_shape, 1);
    const uint32_t Ce3 = GetDim(wex3_shape, 0);
    const uint32_t Cs_check3 = GetDim(wex3_shape, 1);

    if (Cin != Cin_check) return ge::GRAPH_FAILED;
    if (Cs != Cs_check1 || Cs != Cs_check3) return ge::GRAPH_FAILED;
    if (bsq_shape->GetOriginShape().GetShapeSize() != Cs) return ge::GRAPH_FAILED;
    if (bex1_shape->GetOriginShape().GetShapeSize() != Ce1) return ge::GRAPH_FAILED;
    if (bex3_shape->GetOriginShape().GetShapeSize() != Ce3) return ge::GRAPH_FAILED;

    tiling.set_n(N);
    tiling.set_c_in(Cin);
    tiling.set_h(H);
    tiling.set_w(W);
    tiling.set_c_squeeze(Cs);
    tiling.set_c_expand1(Ce1);
    tiling.set_c_expand3(Ce3);

    const uint32_t wsPerSampleBytes = Cs * H * W * sizeof(float);
    tiling.set_wsPerSampleBytes(wsPerSampleBytes);

    uint32_t blockDim = N;
    if (blockDim < 1u) blockDim = 1u;
    if (blockDim > 32u) blockDim = 32u; // cap per hardware
    context->SetBlockDim(blockDim);
    tiling.set_blockDim(blockDim);

